parameters.jsCode:
// Generate insurance-themed social media content
const today = new Date();
const dayOfWeek = today.getDay();
const month = today.getMonth();

// Content calendar based on day/month
const contentTemplates = {
  monday: {
    topic: 'Medicare/Life Insurance Education',
    hooks: [
      'Starting a new week with a reminder: Your health is your wealth. Have you reviewed your Medicare coverage lately?',
      'Monday motivation: The best time to plan for healthcare is before you need it. When did you last review your coverage?',
      'Medicare question: Do you know the difference between Medicare Advantage and Medicare Supplement? Most people don\'t — and that\'s okay! We\'re here to help.'
    ]
  },
  tuesday: {
    topic: 'Final Expense / Life Insurance',
    hooks: [
      'A question worth asking: Has your family discussed final expense planning? It\'s not fun, but it\'s one of the most loving things you can do.',
      'Life insurance isn\'t about death — it\'s about protecting the people you love while they\'re still here.',
      'Final expense insurance: A small monthly premium can mean your family doesn\'t have to worry about burial costs.'
    ]
  },
  wednesday: {
    topic: 'Medicare Enrollment / Dates',
    hooks: [
      '⏰ Did you know? Medicare Annual Enrollment runs October 15 – December 7. If you\'re on Medicare, now is the time to review your plan.',
      'Turning 65 soon? Your Initial Enrollment Period starts 3 months before your birthday month. Don\'t miss it!',
      'Medicare enrollment mistakes can be costly. Here\'s what you need to know before you enroll...'
    ]
  },
  thursday: {
    topic: 'Health & Wellness Connection',
    hooks: [
      'Your health and your insurance coverage are more connected than you think. Regular checkups + right coverage = peace of mind.',
      'Prevention is the best medicine — but it still costs something. Make sure you\'re covered!',
      'Health tip: An ounce of prevention is worth a pound of cure. And the right insurance makes prevention affordable.'
    ]
  },
  friday: {
    topic: 'Client Success / Testimonial Friday',
    hooks: [
      '🎉 Success story: "I saved $200/month on my Medicare plan!" If you\'d like a free quote review, let us know.',
      'Friday feelings: Peace of mind about your healthcare coverage is one of the best gifts you can give yourself.',
      'TGIF! Questions about Medicare, health insurance, or life insurance? Drop them below — we\'re happy to help!'
    ]
  },
  saturday: {
    topic: 'Weekend Inspiration',
    hooks: [
      'Weekend reading: The top 3 Medicare mistakes people make (and how to avoid them).',
      'Saturday thought: Insurance is like a parachute. You don\'t want to find out you needed it and didn\'t have it.',
      'Use your weekend time wisely: Review your coverage. It takes 15 minutes and could save you thousands.'
    ]
  },
  sunday: {
    topic: 'Sunday Prep / Coming Week',
    hooks: [
      'Sunday prep: Make a list of questions about your insurance for the week ahead. We\'re here to answer them.',
      'The new week is coming. Make sure your health coverage is ready for whatever comes.',
      'Self-care Sunday: Part of taking care of yourself is making sure you\'re protected financially.'
    ]
  }
};

const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const template = contentTemplates[dayNames[dayOfWeek]];

// Rotate hooks based on day of year
const dayOfYear = Math.floor((today - new Date(today.getFullYear(), 0, 0)) / (24 * 60 * 60 * 1000));
const hookIndex = dayOfYear % template.hooks.length;
const hook = template.hooks[hookIndex];

// Call to action
const ctas = [
  '📞 Questions? DM us or call 813-863-5917',
  '💬 Comment below if you\'d like to learn more!',
  '🔖 Save this post for later!',
  '📩 Send us a message for a free quote review',
  '👇 Tag someone who should see this!'
];
const cta = ctas[dayOfYear % ctas.length];

// Hashtags
const hashtags = '#Medicare #HealthInsurance #LifeInsurance #FinalExpense #InsurancePlanning #BuckalewFinancial';

return {
  content: `${hook}\n
${cta}\n
${hashtags}`,
  topic: template.topic,
  hook: hook,
  dayOfWeek: dayNames[dayOfWeek],
  characterCount: `${hook}\n\n${cta}\n\n${hashtags}`.length,
  scheduledTime: dayOfWeek === 0 || dayOfWeek === 6 ? 'Saturday/Sunday' : 'Weekday'
};

// For long content, split into thread
const c = $input.first().json;
return {
  ...c,
  thread: true,
  mainTweet: c.hook.substring(0, 260) + '...',
  replyTweet: `(1/2) ${c.hook}\n\nContinuing...`,
  finalTweet: `(2/2) ${c.cta}\n\n${c.content.split('\n\n').pop()}`, // hashtags
  content: `[Thread] ${c.content}`
};

